/**
 * Checks each scenario URL and writes backstop.filtered.json
 * containing only pages that return a non-404 response.
 * Runs automatically before every backstop command via run.sh.
 */

const fs = require('fs');

const config = JSON.parse(fs.readFileSync('/src/backstop.json', 'utf8'));

async function pageExists(url) {
  try {
    const res = await fetch(url, {
      method: 'HEAD',
      redirect: 'follow',
      signal: AbortSignal.timeout(5000),
    });
    return res.status !== 404;
  } catch {
    return false;
  }
}

(async () => {
  const uniqueUrls = [...new Set(config.scenarios.map((s) => s.url))];
  const statusMap = {};

  await Promise.all(
    uniqueUrls.map(async (url) => {
      statusMap[url] = await pageExists(url);
    })
  );

  const active = config.scenarios.filter((s) => statusMap[s.url]);
  const skipped = config.scenarios.filter((s) => !statusMap[s.url]);

  if (skipped.length) {
    console.log(`\nSkipping ${skipped.length} scenario(s) — page not found:`);
    skipped.forEach((s) => console.log(`  - ${s.label}`));
  }

  console.log(`\nRunning ${active.length} of ${config.scenarios.length} scenarios.\n`);

  const filtered = { ...config, scenarios: active };
  fs.writeFileSync('/src/backstop.filtered.json', JSON.stringify(filtered, null, 2));
})();

