/**
 * Generates backstop.json scenarios from page-*.php template files.
 * Preserves any existing scenario configs (e.g. custom URLs).
 * New scenarios get the default ?pagename={slug} URL pattern.
 *
 * Run standalone: node backstop/generate-backstop.js
 * Also called automatically by build.js during yarn build.
 */

const fs = require('fs');
const path = require('path');

const srcDir = path.resolve(__dirname, '../buy-honehealth-com/themes/HoneLandingPages/src');
const configPath = path.resolve(__dirname, 'backstop.json');

